import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\lib\\\\menuConfig.ts', ''),
  ('src\\\\app\\\\page.tsx', ''),
  ('src\\\\app\\\\sobre\\\\page.tsx', ''),
  ('src\\\\app\\\\contato\\\\page.tsx', ''),
  ('src\\\\app\\\\loja\\\\page.tsx', ''),
  ('src\\\\components\\\\loja\\\\ProdutoDetalhes.tsx', ''),
  ('src\\\\components\\\\layout\\\\Header.tsx', ''),
  ('src\\\\components\\\\layout\\\\Footer.tsx', ''),
  ('src\\\\app\\\\checkout\\\\page.tsx', ''),
  ('src\\\\app\\\\pedidos\\\\sucesso\\\\page.tsx', ''),
  ('src\\\\app\\\\pedidos\\\\falha\\\\page.tsx', ''),
  ('src\\\\app\\\\pedidos\\\\pendente\\\\page.tsx', ''),
  ('src\\\\app\\\\admin-loja\\\\page.tsx', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)
print()
print(f"Total: {ok}/13 arquivos corrigidos com acentuacao correta")
print("Agora rode: npm run build")